const { execSync } = require('child_process');

try {
  const timestamp = new Date().toISOString().replace(/[:.]/g, '').replace('T', '_').slice(0, 15);
  const file = `/backups/backup_cokalbarunning_${timestamp}.sql.gz`;
  execSync(
    `pg_dump -h shared-postgres-db -U cokalba cokalba_running | gzip > ${file}`,
    { encoding: 'utf8', shell: '/bin/sh', env: { ...process.env, PGPASSWORD: 'secret' } }
  );
  return [{ json: { success: true, file } }];
} catch (e) {
  return [{ json: { success: false, error: e.message } }];
}

const { execSync } = require('child_process');

try {
  const result = execSync(
    "find /backups -name 'backup_cokalbarunning_*.sql.gz' -mtime +7 -delete -print",
    { encoding: 'utf8', shell: '/bin/sh' }
  );
  const deleted = result.trim();
  return [{ json: { success: true, deleted: deleted || 'ninguno' } }];
} catch (e) {
  return [{ json: { success: false, error: e.message } }];
}
